<?php require 'auth.php'; require_login(); $d=content(); if($_POST){ foreach($d['site'] as $k=>$v){ if(isset($_POST[$k])) $d['site'][$k]=$_POST[$k]; } save_content($d); $msg='Saved successfully'; } $s=$d['site']; ?>
<!doctype html><html><head><title>Edit Site</title><link rel="stylesheet" href="../assets/css/style.css"><style>.wrap{max-width:900px;margin:30px auto}input,textarea{width:100%;padding:10px;margin:6px 0 14px;border:1px solid #ccc;border-radius:8px}textarea{min-height:90px}</style></head><body><div class="wrap"><h1>Company & Contact Details</h1><?php if(!empty($msg)) echo '<p style="color:green">'.$msg.'</p>'; ?><form method="post"><?php foreach($s as $k=>$v): ?><label><?=e(ucwords(str_replace('_',' ',$k)))?></label><?php if(strlen($v)>80): ?><textarea name="<?=e($k)?>"><?=e($v)?></textarea><?php else: ?><input name="<?=e($k)?>" value="<?=e($v)?>"><?php endif; ?><?php endforeach; ?><button class="btn">Save</button> <a href="index.php">Back</a></form></div></body></html>
